-- =============================================
-- 1. DATA_DUMP_RPT_ACCOUNT_CLIENT
-- =============================================
-- Script for DATA_DUMP_RPT_ACCOUNT_CLIENT

-- Insert file type configuration (prevent duplicate)
SELECT 999, (SELECT ID_FILE_TYPE FROM TFM_FILE_TYPE WHERE TYPE_NAME = 'DATA_DUMP_RPT_ACCOUNT_CLIENT'), 223, N'CSV', N'.csv', null, 0
WHERE NOT EXISTS (
    SELECT 1 FROM IBC_ISSUER_FILE_TYPE
    WHERE ID_ISSUER = 999
    AND ID_FILE_TYPE = (SELECT ID_FILE_TYPE FROM TFM_FILE_TYPE WHERE TYPE_NAME = 'DATA_DUMP_RPT_ACCOUNT_CLIENT')
    AND ID_PROCESS = 223
);

-- Deletes existing properties to avoid unused extras
DELETE [IBC_ISSUER_FILE_TYPE_FIELDS]
WHERE ID_ISSUER = 999
AND ID_FILE_TYPE = (
    SELECT ID_FILE_TYPE
    FROM TFM_FILE_TYPE
    WHERE TYPE_NAME = 'DATA_DUMP_RPT_ACCOUNT_CLIENT'
);

-- Account Client fields

